/**
 * Database types for the public schema.
 *
 * Hand-written to match supabase/migrations/0001_init.sql. Regenerate via
 *   npx supabase gen types typescript --project-id gdinummzvbwjfdesqfpt
 * once a personal access token is set (`supabase login` or
 * SUPABASE_ACCESS_TOKEN env var).
 *
 * Conventions:
 * - All `id` columns are TEXT (uuid v4 strings generated by the app).
 * - Timestamps are ISO strings as returned by PostgREST.
 * - `numeric` columns come back as `number` from supabase-js v2.
 * - JSONB columns are typed as the embedded shapes used in src/lib/dev-store/*.
 */

// -----------------------------------------------------------------------------
// JSONB sub-shapes (mirror dev-store types so adapters can pass straight through)
// -----------------------------------------------------------------------------

export type ProjectTaskRow = {
    id: string;
    title: string;
    done: boolean;
    assignee: string;
    phase: string;
    createdAt: string;
};

export type ProjectDeliverableRow = {
    id: string;
    title: string;
    url: string;
    notes: string;
    phase: string;
    approvedAt: string | null;
    approvedBy: string;
    createdAt: string;
};

export type ProjectSignoffRow = {
    signedAt: string | null;
    signedBy: string;
    notes: string;
};

export type OnboardingFileRow = {
    name: string;
    size: number;
    type: string;
    url: string;
};

export type AuditChangeRow = {
    field: string;
    before: unknown;
    after: unknown;
};

// -----------------------------------------------------------------------------
// Per-table Row tuples (Insert/Update default to Partial<Row>)
// -----------------------------------------------------------------------------

type Tbl<R> = {
    Row: R;
    Insert: Partial<R> & { id?: string };
    Update: Partial<R>;
    Relationships: [];
};

