// -----------------------------------------------------------------------------
// Database type expected by supabase-js
// -----------------------------------------------------------------------------

export type Database = {
    public: {
        Tables: {
            agency_profile: Tbl<AgencyProfileRow>;
            services: Tbl<ServiceRow>;
            clients: Tbl<ClientRow>;
            team_members: Tbl<TeamMemberRow>;
            leads: Tbl<LeadRow>;
            onboarding_submissions: Tbl<OnboardingSubmissionRow>;
            projects: Tbl<ProjectRow>;
            workflow_templates: Tbl<WorkflowTemplateRow>;
            invoices: Tbl<InvoiceRow>;
            invoice_items: Tbl<InvoiceItemRow>;
            campaigns: Tbl<CampaignRow>;
            campaign_metrics: Tbl<CampaignMetricRow>;
            content_posts: Tbl<ContentPostRow>;
            seo_articles: Tbl<SeoArticleRow>;
            notifications: Tbl<NotificationRow>;
            audit_events: Tbl<AuditEventRow>;
        };
        Views: Record<string, never>;
        // Permissive Functions map: the new schema declares no RPCs yet, but
        // legacy code still calls `supabase.rpc("user_has_permission", …)`
        // behind a DEV_AUTH_BYPASS guard. Loose typing keeps the call site
        // compiling until permissions land in I1.15.
        Functions: {
            [name: string]: {
                Args: Record<string, unknown>;
                Returns: unknown;
            };
        };
        Enums: Record<string, never>;
        CompositeTypes: Record<string, never>;
    };
};
